mapper.select:
SELECT b.*, build.name as buildingName, u.name as unitName, r.room_num as roomNum, o.name as ownerName FROM bus_bill b LEFT JOIN bus_room r ON b.room_id = r.id LEFT JOIN bus_unit u ON r.unit_id = u.id LEFT JOIN bus_building build ON u.building_id = build.id -- 关联房主：relation_type = 1 代表业主本人 LEFT JOIN bus_room_owner ro ON r.id = ro.room_id AND ro.relation_type = 1 LEFT JOIN bus_owner o ON ro.owner_id = o.id
AND o.user_id = #{query.userId}
AND b.year = #{query.year}
AND b.pay_status = #{query.payStatus}
AND r.room_num LIKE CONCAT('%', #{query.roomNum}, '%')
AND o.name LIKE CONCAT('%', #{query.ownerName}, '%')
AND build.id = #{query.buildingId}
AND u.id = #{query.unitId}
ORDER BY b.year DESC, b.month DESC, b.create_time DESC
